class Solution {
    public int primePalindrome(int n) {
        while (true) {
            if (isPalindrome(n) && isPrime(n)) {
                return n;
            }
            n++;
            if (n > 1 && n != 11 && isPowerOfTenMinusOne(n)) {
                n = nextPowerOfTen(n);
            }
        }
    }

    private boolean isPalindrome(int n) {
        String str = Integer.toString(n);
        int left = 0, right = str.length() - 1;
        while (left < right) {
            if (str.charAt(left) != str.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }

    private boolean isPrime(int n) {
        if (n <= 1) {
            return false;
        }
        if (n == 2) {
            return true;
        }
        if (n % 2 == 0) {
            return false;
        }
        for (int i = 3; i * i <= n; i += 2) {
            if (n % i == 0) {
                return false;
            }
        }
        return true;
    }

    private boolean isPowerOfTenMinusOne(int n) {
        String str = Integer.toString(n);
        for (char c : str.toCharArray()) {
            if (c != '9') {
                return false;
            }
        }
        return true;
    }

    private int nextPowerOfTen(int n) {
        String str = Integer.toString(n);
        StringBuilder sb = new StringBuilder();
        sb.append('1');
        for (int i = 0; i < str.length(); i++) {
            sb.append('0');
        }
        if (str.length() % 2 == 0) {
            sb.append('1');
            for (int i = 0; i < str.length(); i++) {
                sb.append('0');
            }
        }
        return Integer.parseInt(sb.toString());
    }
}
